    34→
    35→// Escape codes for colorizing output.
    36→const (
    37→	Reset  = "\033[0m"
    38→	Red    = "\033[31m"
    39→	Green  = "\033[32m"
    40→	Yellow = "\033[33m"
    41→	Blue   = "\033[34m"
    42→	Purple = "\033[35m"
    43→	Cyan   = "\033[36m"
    44→	Gray   = "\033[37m"
    45→	White  = "\033[97m"
    46→)
    47→
    48→// PrettyHandlerOptions provides options for the PrettyHandler
    49→type PrettyHandlerOptions struct {
    50→	AddSource   bool
    51→	Level       slog.Leveler
    52→	ReplaceAttr func([]string, slog.Attr) slog.Attr
    53→	Colorize    bool
    54→}
    55→
    56→// PrettyHandler is an slog.Handler that pretty-prints log records using color.
    57→// Based upon:
    58→//
    59→//	https://github.com/golang/example/blob/master/slog-handler-guide/README.md
    60→type PrettyHandler struct {
    61→	pool *sync.Pool
    62→	opts *PrettyHandlerOptions
    63→	goas []groupOrAttrs
    64→	mu   *sync.Mutex
    65→	out  io.Writer
    66→}
    67→
    68→// groupOrAttrs holds either a group name or a list of slog.Attrs.
    69→type groupOrAttrs struct {
    70→	group string      // group name if non-empty
    71→	attrs []slog.Attr // attrs if non-empty
    72→}
    73→
    74→// needsQuoting reports whether the string s needs quoting.
    75→func needsQuoting(s string) bool {
    76→	if len(s) == 0 {
    77→		return true
    78→	}
    79→	for _, r := range s {
    80→		if unicode.IsSpace(r) || strings.ContainsRune("!\"#$%&'()*+,-/:;<=>?@[\\]^`{|}~", r) {
    81→			return true
    82→		}
    83→	}
    84→	return false
    85→}
    86→
    87→// initPool initializes the pool of buffers for the PrettyHandler.
    88→func (h *PrettyHandler) initPool() {
    89→	h.pool = &sync.Pool{
    90→		New: func() any {
    91→			b := make([]byte, 0, 1024)
    92→			return &b
    93→		},
    94→	}
    95→}
    96→
    97→// allocBuf returns a buffer from the pool.
    98→func (h *PrettyHandler) allocBuf() *[]byte {
    99→	if h.pool == nil {
   100→		b := make([]byte, 0, 1024)
   101→		return &b
   102→	}
   103→
   104→	return h.pool.Get().(*[]byte)
   105→}
   106→
   107→// freeBuf returns a buffer to the pool.
   108→func (h *PrettyHandler) freeBuf(b *[]byte) {
   109→	if h.pool == nil {
   110→		return
   111→	}
   112→
   113→	// To reduce peak allocation, return only smaller buffers to the pool.
   114→	const maxBufferSize = 16 << 10
   115→	if cap(*b) <= maxBufferSize {
   116→		*b = (*b)[:0]
   117→		h.pool.Put(b)
   118→	}
   119→}
   120→
   121→// qappendf appends a quoted string to the given buffer.
   122→func qappendf(buf []byte, groups []string, val string) []byte {
   123→	pstr := strings.Join(groups, ".")
   124→	if len(groups) > 0 {
   125→		pstr = fmt.Sprintf("%s.", pstr)
   126→	}
   127→	str := fmt.Sprintf("%s%s", pstr, val)
   128→	if needsQuoting(str) {
   129→		buf = fmt.Appendf(buf, "%q", str)
   130→	} else {
   131→		buf = fmt.Appendf(buf, "%s", str)
   132→	}
   133→	return buf
   134→}
   135→
   136→// appendAttr appends an attribute to the given buffer.
   137→func (h *PrettyHandler) appendAttr(buf []byte, a slog.Attr, groups []string) []byte {
   138→	// Resolve the Attr's value before doing anything else.
   139→	a.Value = a.Value.Resolve()
   140→
   141→	// Call ReplaceAttr, if provided.
   142→	if rep := h.opts.ReplaceAttr; rep != nil && a.Value.Kind() != slog.KindGroup {
   143→		gs := slices.Clone(groups)
   144→		a = rep(gs, a)
   145→		a.Value = a.Value.Resolve()
   146→	}
   147→
   148→	// Ignore empty Attrs.
   149→	if a.Equal(slog.Attr{}) {
   150→		return buf
   151→	}
   152→
   153→	switch a.Value.Kind() {
   154→	case slog.KindString:
   155→		// Prefix the attribute with a space
   156→		buf = append(buf, " "...)
   157→
   158→		// Output key=value
   159→		buf = qappendf(buf, groups, a.Key)
   160→		buf = append(buf, "="...)
   161→		buf = qappendf(buf, []string{}, a.Value.String())
   162→	case slog.KindTime:
   163→		// Prefix the attribute with a space
   164→		buf = append(buf, " "...)
   165→
   166→		// Output key=value
   167→		buf = qappendf(buf, groups, a.Key)
   168→		buf = append(buf, "="...)
   169→
   170→		// Write times in a standard way, without the monotonic time.
   171→		buf = fmt.Appendf(buf, "%s", a.Value.Time().Format(time.RFC3339Nano))
   172→	case slog.KindGroup:
   173→		attrs := a.Value.Group()
   174→		// Ignore empty groups.
   175→		if len(attrs) == 0 {
   176→			return buf
   177→		}
   178→		// If the key is non-empty, add group to groups.
   179→		if a.Key != "" {
   180→			groups = append(groups, a.Key)
   181→		}
   182→
   183→		// Output group's attributes.
   184→		for _, ga := range attrs {
   185→			buf = h.appendAttr(buf, ga, groups)
   186→		}
   187→	default:
   188→		// Prefix the attribute with a space
   189→		buf = append(buf, " "...)
   190→
   191→		// Output key=value
   192→		buf = qappendf(buf, groups, a.Key)
   193→		buf = append(buf, "="...)
   194→		buf = fmt.Appendf(buf, "%s", a.Value)
   195→	}
   196→
   197→	return buf
   198→}
   199→
   200→// Enabled returns true if the logging level is enabled.
   201→func (h *PrettyHandler) Enabled(ctx context.Context, level slog.Level) bool {
   202→	return level >= h.opts.Level.Level()
   203→}
   204→
   205→// Handle writes the record to the output.
   206→func (h *PrettyHandler) Handle(ctx context.Context, r slog.Record) error {
   207→	// Allocate a buffer for the record from the pool.
   208→	bufp := h.allocBuf()
   209→	buf := *bufp
   210→	defer func() {
   211→		*bufp = buf
   212→		h.freeBuf(bufp)
   213→	}()
   214→
   215→	groups := make([]string, 0)
   216→
   217→	if h.opts.Colorize {
   218→		// Set the color based on the level of the record.
   219→		if r.Level == slog.LevelError {
   220→			buf = append(buf, Red...)
   221→		} else if r.Level == slog.LevelWarn {
   222→			buf = append(buf, Yellow...)
   223→		} else if r.Level == slog.LevelDebug {
   224→			buf = append(buf, Cyan...)
   225→		} else {
   226→			// Default to white.
   227→			buf = append(buf, White...)
   228→		}
   229→	}
   230→
   231→	var a slog.Attr
   232→
   233→	// Time
   234→	if !r.Time.IsZero() {
   235→		if rep := h.opts.ReplaceAttr; rep != nil {
   236→			// Call ReplaceAttr, if provided.
   237→			gs := slices.Clone(groups)
   238→			a = rep(gs, slog.Time(slog.TimeKey, r.Time))
   239→			a.Value = a.Value.Resolve()
   240→			if !a.Equal(slog.Attr{}) {
   241→				if a.Key == slog.TimeKey {
   242→					buf = qappendf(buf, groups, a.Value.String())
   243→					buf = append(buf, " "...)
   244→				} else {
   245→					buf = h.appendAttr(buf, a, groups)
   246→				}
   247→			}
   248→		} else {
   249→			buf = fmt.Appendf(buf, "%s ", r.Time.Format("2006/01/02 15:04:05"))
   250→		}
   251→	}
   252→
   253→	// Level
   254→	if rep := h.opts.ReplaceAttr; rep != nil {
   255→		// Call ReplaceAttr, if provided.
   256→		gs := slices.Clone(groups)
   257→		a = rep(gs, slog.Any(slog.LevelKey, r.Level))
   258→		a.Value = a.Value.Resolve()
   259→		if !a.Equal(slog.Attr{}) {
   260→			if a.Key == slog.LevelKey {
   261→				buf = qappendf(buf, groups, a.Value.String())
   262→				buf = append(buf, " "...)
   263→			} else {
   264→				buf = h.appendAttr(buf, a, groups)
   265→			}
   266→		}
   267→	} else {
   268→		buf = fmt.Appendf(buf, "%s ", r.Level)
   269→	}
   270→
   271→	// Message
   272→	if rep := h.opts.ReplaceAttr; rep != nil {
   273→		// Call ReplaceAttr, if provided.
   274→		gs := slices.Clone(groups)
   275→		a = rep(gs, slog.Any(slog.MessageKey, r.Message))
   276→		a.Value = a.Value.Resolve()
   277→		if !a.Equal(slog.Attr{}) {
   278→			if a.Key == slog.MessageKey {
   279→				buf = fmt.Appendf(buf, "%s", a.Value.String())
   280→			} else {
   281→				buf = h.appendAttr(buf, a, groups)
   282→			}
   283→		}
   284→	} else {
   285→		buf = fmt.Appendf(buf, "%s", r.Message)
   286→	}
   287→
   288→	// Source
   289→	if h.opts.AddSource && r.PC != 0 {
   290→		fs := runtime.CallersFrames([]uintptr{r.PC})
   291→		f, _ := fs.Next()
   292→		buf = h.appendAttr(buf, slog.String(slog.SourceKey, fmt.Sprintf("%s:%d", f.File, f.Line)), groups)
   293→	}
   294→
   295→	// Handle state from WithGroup and WithAttrs.
   296→
   297→	goas := h.goas
   298→	if r.NumAttrs() == 0 {
   299→		// If the record has no Attrs, remove groups at the end of the list; they are empty.
   300→		for len(goas) > 0 && goas[len(goas)-1].group != "" {
   301→			goas = goas[:len(goas)-1]
   302→		}
   303→	}
   304→	for _, goa := range goas {
   305→		if goa.group != "" {
   306→			groups = append(groups, goa.group)
   307→		} else {
   308→			for _, a := range goa.attrs {
   309→				buf = h.appendAttr(buf, a, groups)
   310→			}
   311→		}
   312→	}
   313→	r.Attrs(func(a slog.Attr) bool {
   314→		buf = h.appendAttr(buf, a, groups)
   315→		return true
   316→	})
   317→
   318→	// Newline and reset color.
   319→	if h.opts.Colorize {
   320→		buf = append(buf, Reset...)
   321→	}
   322→	buf = append(buf, "\n"...)
