    22→
    23→// RunAll runs all integration tests
    24→func (i *IntegrationTests) RunAll() []TestResult {
    25→	var results []TestResult
    26→
    27→	tests := []struct {
    28→		name string
    29→		fn   func() error
    30→	}{
    31→		{"PostDocumentReturnsURI", i.TestPostDocumentReturnsURI},
    32→		{"PostDocumentCreatesDocument", i.TestPostDocumentCreatesDocument},
    33→		{"PostDocumentNestedCollection", i.TestPostDocumentNestedCollection},
    34→		{"PostDocumentWithData", i.TestPostDocumentWithData},
    35→		{"PatchArrayAddDuplicate", i.TestPatchArrayAddDuplicate},
    36→		{"PatchObjectAddNested", i.TestPatchObjectAddNested},
    37→		{"PatchMultipleOperations", i.TestPatchMultipleOperations},
    38→		{"PatchResponseFormat", i.TestPatchResponseFormat},
    39→		{"OptionsCollectionPath", i.TestOptionsCollectionPath},
    40→		{"OptionsCORSHeaders", i.TestOptionsCORSHeaders},
    41→		{"AuthLoginReturnsToken", i.TestAuthLoginReturnsToken},
    42→		{"AuthUnauthorizedWithoutToken", i.TestAuthUnauthorizedWithoutToken},
    43→		{"CollectionQueryWithIntervalExclusive", i.TestCollectionQueryWithIntervalExclusive},
    44→		{"CollectionQueryOrdering", i.TestCollectionQueryOrdering},
    45→		{"DocumentMetadataCreatedBy", i.TestDocumentMetadataCreatedBy},
    46→		{"DocumentMetadataLastModifiedBy", i.TestDocumentMetadataLastModifiedBy},
    47→		{"ErrorResponseJSON", i.TestErrorResponseJSON},
    48→		{"Error400BadRequest", i.TestError400BadRequest},
    49→		{"Error404NotFound", i.TestError404NotFound},
    50→	}
    51→
    52→	for _, test := range tests {
    53→		start := time.Now()
    54→		err := test.fn()
    55→		duration := time.Since(start)
    56→
    57→		result := TestResult{
    58→			Name:     test.name,
    59→			Passed:   err == nil,
    60→			Duration: duration,
    61→		}
    62→		if err != nil {
    63→			result.Error = err.Error()
    64→		}
    65→		results = append(results, result)
    66→
    67→		if i.t != nil {
    68→			if err != nil {
    69→				i.t.Errorf("%s: %v", test.name, err)
    70→			} else {
    71→				i.t.Logf("%s: PASSED (%v)", test.name, duration)
    72→			}
    73→		}
    74→	}
    75→
    76→	return results
    77→}
