    81→func (i *IntegrationTests) TestPostDocumentReturnsURI() error {
    82→	dbName := GenerateTestDBName()
    83→	defer i.harness.DeleteDatabase(dbName)
    84→
    85→	if err := i.harness.CreateDatabase(dbName); err != nil {
    86→		return err
    87→	}
    88→
    89→	doc := map[string]interface{}{"data": "test"}
    90→	resp, err := i.harness.HTTPRequest("POST", "/v1/"+dbName+"/", doc)
    91→	if err != nil {
    92→		return err
    93→	}
    94→
    95→	// POST is optional - if server returns 405, skip this test
    96→	if resp.StatusCode == http.StatusMethodNotAllowed {
    97→		return nil
    98→	}
    99→
   100→	if resp.StatusCode != http.StatusCreated && resp.StatusCode != http.StatusOK {
   101→		return fmt.Errorf("expected status 201 or 200, got %d: %s", resp.StatusCode, string(resp.Body))
   102→	}
   103→
   104→	result, err := resp.JSON()
   105→	if err != nil {
   106→		return fmt.Errorf("failed to parse response: %w", err)
   107→	}
   108→
   109→	// Check for uri field
   110→	uri, hasUri := result["uri"].(string)
   111→	path, hasPath := result["path"].(string)
   112→
   113→	if !hasUri && !hasPath {
   114→		return fmt.Errorf("response missing uri/path field: %v", result)
   115→	}
   116→
   117→	// Just verify uri/path is non-empty (the server may strip the db prefix per P2 spec)
   118→	if hasUri && uri == "" {
   119→		return fmt.Errorf("uri field is empty")
   120→	}
   121→	if hasPath && path == "" {
   122→		return fmt.Errorf("path field is empty")
   123→	}
   124→
   125→	return nil
   126→}
