// Package skiplist implements a concurrent skip list with lazy synchronization
// and atomics, as required by the OwlDB project specification.
//
// The skip list uses:
//   - Lazy synchronization: nodes are logically deleted (marked) before
//     being physically removed from the list.
//   - Per-node mutexes for insertion/deletion.
//   - Atomic flags for 'marked' (logically deleted) and 'fullyLinked' states.
//   - Go generics with cmp.Ordered keys and any values.
package skiplist

import (
	"cmp"
	"context"
	"math"
	"math/rand"
	"sync"
	"sync/atomic"
)

const maxLevel = 16

// UpdateCheck is a function called by Upsert while holding the target node's
// lock. It receives the key, the current value (or zero value if not exists),
// and whether a value already exists. It returns the new value or an error.
type UpdateCheck[K cmp.Ordered, V any] func(key K, currValue V, exists bool) (newValue V, err error)

// Pair is a key-value pair returned by Query.
type Pair[K cmp.Ordered, V any] struct {
	Key   K
	Value V
}

// DBIndex is the interface for the skip list.
type DBIndex[K cmp.Ordered, V any] interface {
	Upsert(key K, check UpdateCheck[K, V]) (updated bool, err error)
	Remove(key K) (removedValue V, removed bool)
	Find(key K) (foundValue V, found bool)
	Query(ctx context.Context, start K, end K) (results []Pair[K, V], err error)
}

// node is a single node in the skip list.
type node[K cmp.Ordered, V any] struct {
	key        K
	value      V
	topLevel   int
	nexts      [maxLevel]*node[K, V]
	marked     atomic.Bool // logically deleted
	fullyLinked atomic.Bool // physically linked at all levels
	mu         sync.Mutex
}

// SkipList is a concurrent skip list with lazy synchronization.
type SkipList[K cmp.Ordered, V any] struct {
	head *node[K, V]
	tail *node[K, V]
}

// New creates a new SkipList.
func New[K cmp.Ordered, V any]() *SkipList[K, V] {
	head := &node[K, V]{topLevel: maxLevel - 1}
	tail := &node[K, V]{topLevel: maxLevel - 1}
	for i := 0; i < maxLevel; i++ {
		head.nexts[i] = tail
	}
	head.fullyLinked.Store(true)
	tail.fullyLinked.Store(true)
	return &SkipList[K, V]{head: head, tail: tail}
}

// randomLevel returns a random level for a new node.
func randomLevel() int {
	level := 0
	for level < maxLevel-1 && rand.Float64() < 0.5 {
		level++
	}
	return level
}

// find locates preds and succs for the given key at all levels.
// Returns the level at which the key was found, or -1.
func (s *SkipList[K, V]) find(key K, preds, succs []*node[K, V]) int {
	foundLevel := -1
	pred := s.head
	for level := maxLevel - 1; level >= 0; level-- {
		curr := pred.nexts[level]
		for curr != s.tail && cmp.Compare(curr.key, key) < 0 {
			pred = curr
			curr = pred.nexts[level]
		}
		if foundLevel == -1 && curr != s.tail && cmp.Compare(curr.key, key) == 0 {
			foundLevel = level
		}
		preds[level] = pred
		succs[level] = curr
	}
	return foundLevel
}

// Upsert inserts or updates the value for the given key.
// The check function is called with the node's lock held (if node exists).
func (s *SkipList[K, V]) Upsert(key K, check UpdateCheck[K, V]) (updated bool, err error) {
	var preds [maxLevel]*node[K, V]
	var succs [maxLevel]*node[K, V]

	for {
		foundLevel := s.find(key, preds[:], succs[:])

		if foundLevel != -1 {
			// Key already exists
			nodeFound := succs[foundLevel]
			if nodeFound.marked.Load() {
				// Node is being deleted, retry
				continue
			}
			// Wait until fully linked
			for !nodeFound.fullyLinked.Load() {
			}
			// Lock the node and call check function
			nodeFound.mu.Lock()
			if nodeFound.marked.Load() {
				nodeFound.mu.Unlock()
				continue
			}
			newVal, checkErr := check(key, nodeFound.value, true)
			if checkErr != nil {
				nodeFound.mu.Unlock()
				return false, checkErr
			}
			nodeFound.value = newVal
			nodeFound.mu.Unlock()
			return true, nil
		}

		// Key not found - insert new node
		topLevel := randomLevel()

		// Lock all necessary predecessors
		valid := true
		var lockedPreds []*node[K, V]

		for level := 0; level <= topLevel; level++ {
			pred := preds[level]
			succ := succs[level]

			pred.mu.Lock()
			lockedPreds = append(lockedPreds, pred)

			if pred.marked.Load() || succ.marked.Load() || pred.nexts[level] != succ {
				valid = false
				break
			}
		}

		if !valid {
			for _, p := range lockedPreds {
				p.mu.Unlock()
			}
			continue
		}

		// Call check to get initial value
		var zero V
		newVal, checkErr := check(key, zero, false)
		if checkErr != nil {
			for _, p := range lockedPreds {
				p.mu.Unlock()
			}
			return false, checkErr
		}

		// Create new node
		newNode := &node[K, V]{
			key:      key,
			value:    newVal,
			topLevel: topLevel,
		}

		// Link new node at all levels
		for level := 0; level <= topLevel; level++ {
			newNode.nexts[level] = succs[level]
			preds[level].nexts[level] = newNode
		}
		newNode.fullyLinked.Store(true)

		for _, p := range lockedPreds {
			p.mu.Unlock()
		}
		return false, nil
	}
}

// Remove removes the node with the given key.
// Returns the removed value and true if found, or zero value and false.
func (s *SkipList[K, V]) Remove(key K) (removedValue V, removed bool) {
	var preds [maxLevel]*node[K, V]
	var succs [maxLevel]*node[K, V]
	var victim *node[K, V]
	isMarked := false

	for {
		foundLevel := s.find(key, preds[:], succs[:])

		if isMarked || (foundLevel != -1 && canDelete(succs[foundLevel], foundLevel)) {
			if !isMarked {
				victim = succs[foundLevel]
				victim.mu.Lock()
				if victim.marked.Load() {
					victim.mu.Unlock()
					var zero V
					return zero, false
				}
				victim.marked.Store(true)
				isMarked = true
			}

			// Lock predecessors and physically remove
			var lockedPreds []*node[K, V]
			valid := true
			highestLocked := -1

			for level := 0; level <= victim.topLevel; level++ {
				pred := preds[level]
				if level == 0 || preds[level] != preds[level-1] {
					pred.mu.Lock()
					lockedPreds = append(lockedPreds, pred)
					highestLocked = level
				}
				if pred.marked.Load() || pred.nexts[level] != victim {
					valid = false
					break
				}
			}
			_ = highestLocked

			if !valid {
				for _, p := range lockedPreds {
					p.mu.Unlock()
				}
				continue
			}

			// Physically remove
			for level := victim.topLevel; level >= 0; level-- {
				preds[level].nexts[level] = victim.nexts[level]
			}
			victim.mu.Unlock()
			for _, p := range lockedPreds {
				p.mu.Unlock()
			}
			return victim.value, true
		}
		var zero V
		return zero, false
	}
}

func canDelete[K cmp.Ordered, V any](n *node[K, V], foundLevel int) bool {
	return n.fullyLinked.Load() && n.topLevel == foundLevel && !n.marked.Load()
}

// Find returns the value for the given key, or false if not found.
func (s *SkipList[K, V]) Find(key K) (foundValue V, found bool) {
	var preds [maxLevel]*node[K, V]
	var succs [maxLevel]*node[K, V]
	foundLevel := s.find(key, preds[:], succs[:])
	if foundLevel != -1 {
		n := succs[foundLevel]
		if n.fullyLinked.Load() && !n.marked.Load() {
			return n.value, true
		}
	}
	var zero V
	return zero, false
}

// Query returns all key-value pairs with keys in [start, end] in sorted order.
// Uses math.IsInf trick: if start is "" and end is "" (empty strings), treat as unbounded.
// For generic K: we accept the sentinel values (a key less than all others for start
// and greater than all for end).
//
// The start and end bounds are inclusive. Empty string "" means no bound.
func (s *SkipList[K, V]) Query(ctx context.Context, start K, end K) ([]Pair[K, V], error) {
	var results []Pair[K, V]

	curr := s.head.nexts[0]
	for curr != s.tail {
		select {
		case <-ctx.Done():
			return results, ctx.Err()
		default:
		}

		if !curr.marked.Load() && curr.fullyLinked.Load() {
			key := curr.key
			inRange := true

			// Check if we have a real start bound (use sentinel detection via maxKey/minKey)
			if !isMinSentinel(start) && cmp.Compare(key, start) < 0 {
				inRange = false
			}
			if !isMaxSentinel(end) && cmp.Compare(key, end) > 0 {
				inRange = false
			}

			if inRange {
				results = append(results, Pair[K, V]{Key: key, Value: curr.value})
			}

			// If past end, we can stop (skip list is sorted)
			if !isMaxSentinel(end) && cmp.Compare(key, end) > 0 {
				break
			}
		}
		curr = curr.nexts[0]
	}
	return results, nil
}

// isMinSentinel checks if a key is the minimum sentinel value.
func isMinSentinel[K cmp.Ordered](k K) bool {
	// For strings: empty string "" is treated as "no lower bound"
	// For other types we rely on math.IsInf-style detection
	switch v := any(k).(type) {
	case string:
		return v == ""
	case float64:
		return math.IsInf(v, -1)
	case int:
		return v == math.MinInt
	case int64:
		return v == math.MinInt64
	}
	return false
}

// isMaxSentinel checks if a key is the maximum sentinel value.
func isMaxSentinel[K cmp.Ordered](k K) bool {
	switch v := any(k).(type) {
	case string:
		return v == ""
	case float64:
		return math.IsInf(v, 1)
	case int:
		return v == math.MaxInt
	case int64:
		return v == math.MaxInt64
	}
	return false
}

// Package auth handles authentication via Bearer tokens.
// Tokens expire 1 hour after issuance (or 24+ hours for pre-loaded tokens).
package auth

import (
	"encoding/json"
	"fmt"
	"math/rand"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"
)

const (
	tokenChars  = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789_-"
	tokenLen    = 16
	tokenExpiry = time.Hour
)

// tokenEntry stores a token's username and expiry time.
type tokenEntry struct {
	username string
	expiry   time.Time
}

// Store manages authentication tokens.
type Store struct {
	mu     sync.RWMutex
	tokens map[string]tokenEntry
}

// New creates a new auth Store.
func New() *Store {
	return &Store{tokens: make(map[string]tokenEntry)}
}

// generateToken generates a random token string.
func generateToken() string {
	b := make([]byte, tokenLen)
	for i := range b {
		b[i] = tokenChars[rand.Intn(len(tokenChars))]
	}
	return string(b)
}

// Login creates a new token for the given username and returns it.
func (s *Store) Login(username string) string {
	token := generateToken()
	expiry := time.Now().Add(tokenExpiry)
	s.mu.Lock()
	s.tokens[token] = tokenEntry{username: username, expiry: expiry}
	s.mu.Unlock()
	return token
}

// Logout invalidates a token. Returns false if the token was not found.
func (s *Store) Logout(token string) bool {
	s.mu.Lock()
	defer s.mu.Unlock()
	_, ok := s.tokens[token]
	if ok {
		delete(s.tokens, token)
	}
	return ok
}

// Validate checks if a token is valid and not expired.
// Returns the username and true, or "" and false.
func (s *Store) Validate(token string) (string, bool) {
	s.mu.RLock()
	entry, ok := s.tokens[token]
	s.mu.RUnlock()
	if !ok {
		return "", false
	}
	if time.Now().After(entry.expiry) {
		s.mu.Lock()
		delete(s.tokens, token)
		s.mu.Unlock()
		return "", false
	}
	return entry.username, true
}

// LoadTokenFile loads pre-defined tokens from a JSON file.
// Tokens loaded this way expire 48 hours in the future (effectively never for testing).
func (s *Store) LoadTokenFile(filename string) error {
	data, err := os.ReadFile(filename)
	if err != nil {
		return fmt.Errorf("reading token file: %w", err)
	}
	var tokens map[string]string // username -> token
	if err := json.Unmarshal(data, &tokens); err != nil {
		return fmt.Errorf("parsing token file: %w", err)
	}
	expiry := time.Now().Add(48 * time.Hour)
	s.mu.Lock()
	for username, token := range tokens {
		s.tokens[token] = tokenEntry{username: username, expiry: expiry}
	}
	s.mu.Unlock()
	return nil
}

// ExtractToken extracts the Bearer token from an Authorization header.
func ExtractToken(r *http.Request) string {
	auth := r.Header.Get("Authorization")
	if !strings.HasPrefix(auth, "Bearer ") {
		return ""
	}
	return strings.TrimPrefix(auth, "Bearer ")
}

// Package store implements the in-memory document database.
// Documents are stored hierarchically: databases -> documents -> collections.
// Collections use the concurrent skip list for indexed access.
package store

import (
	"context"
	"encoding/json"
	"errors"
	"fmt"
	"math/rand"
	"time"

	"github.com/RICE-COMP318-FALL24/owldb-p1/jsondata"
	"github.com/RICE-COMP318-FALL24/owldb-p1/skiplist"
	jsonschema "github.com/santhosh-tekuri/jsonschema/v5"
)

// ErrNotFound is returned when a requested resource does not exist.
var ErrNotFound = errors.New("not found")

// ErrAlreadyExists is returned when trying to create a resource that already exists.
var ErrAlreadyExists = errors.New("already exists")

// ErrConflict is returned when a conditional write fails (nooverwrite mode).
var ErrConflict = errors.New("document already exists")

// Metadata holds the document metadata.
type Metadata struct {
	CreatedBy      string `json:"createdBy"`
	CreatedAt      int64  `json:"createdAt"`
	LastModifiedBy string `json:"lastModifiedBy"`
	LastModifiedAt int64  `json:"lastModifiedAt"`
}

// Document represents a stored document with its data and metadata.
type Document struct {
	Data        jsondata.JSONValue
	Meta        Metadata
	collections *skiplist.SkipList[string, *Collection]
	// Subscription channels: notified when this doc changes
	subs *subList
}

// Collection is a named collection of documents.
type Collection struct {
	docs *skiplist.SkipList[string, *Document]
	subs *subList
}

// Database is a top-level database containing documents.
type Database struct {
	docs *skiplist.SkipList[string, *Document]
	subs *subList
}

// subList manages SSE subscriber channels for a resource.
type subList struct {
	// channels to send events to
	mu   chan struct{} // used as mutex via buffered channel
	subs []chan Event
}

func newSubList() *subList {
	s := &subList{mu: make(chan struct{}, 1)}
	s.mu <- struct{}{}
	return s
}

func (s *subList) add(ch chan Event) {
	<-s.mu
	s.subs = append(s.subs, ch)
	s.mu <- struct{}{}
}

func (s *subList) remove(ch chan Event) {
	<-s.mu
	for i, c := range s.subs {
		if c == ch {
			s.subs = append(s.subs[:i], s.subs[i+1:]...)
			break
		}
	}
	s.mu <- struct{}{}
}

func (s *subList) broadcast(e Event) {
	<-s.mu
	for _, ch := range s.subs {
		select {
		case ch <- e:
		default:
		}
	}
	s.mu <- struct{}{}
}

// Event represents an SSE event.
type Event struct {
	Type string // "update" or "delete"
	Path string // document or collection path
	Doc  *DocResult
}

// DocResult is the JSON representation of a document.
type DocResult struct {
	Path string            `json:"path"`
	Doc  jsondata.JSONValue `json:"doc"`
	Meta Metadata          `json:"meta"`
}

// Store is the main database store.
type Store struct {
	databases *skiplist.SkipList[string, *Database]
	schema    *jsonschema.Schema
}

// New creates a new Store with the given JSON schema.
func New(schema *jsonschema.Schema) *Store {
	return &Store{
		databases: skiplist.New[string, *Database](),
		schema:    schema,
	}
}

// validateDocument validates a JSON document against the schema.
func (s *Store) validateDocument(data jsondata.JSONValue) error {
	if s.schema == nil {
		return nil
	}
	return data.Validate(s.schema)
}

// newCollection creates a new empty collection.
func newCollection() *Collection {
	return &Collection{
		docs: skiplist.New[string, *Document](),
		subs: newSubList(),
	}
}

// newDatabase creates a new empty database.
func newDatabase() *Database {
	return &Database{
		docs: skiplist.New[string, *Document](),
		subs: newSubList(),
	}
}

// CreateDatabase creates a new database with the given name.
func (s *Store) CreateDatabase(name string) error {
	_, err := s.databases.Upsert(name, func(key string, curr *Database, exists bool) (*Database, error) {
		if exists {
			return nil, ErrAlreadyExists
		}
		return newDatabase(), nil
	})
	return err
}

// DeleteDatabase deletes the database with the given name.
func (s *Store) DeleteDatabase(name string) error {
	_, removed := s.databases.Remove(name)
	if !removed {
		return ErrNotFound
	}
	return nil
}

// getDatabase returns the database with the given name.
func (s *Store) getDatabase(name string) (*Database, error) {
	db, found := s.databases.Find(name)
	if !found {
		return nil, ErrNotFound
	}
	return db, nil
}

// navigatePath navigates to the parent collection and returns it along with
// the target document/collection name (the last component).
//
// components: parsed path components (already URL-decoded), e.g.:
//   - ["db"] -> database level
//   - ["db", "doc"] -> document in database's top-level collection
//   - ["db", "doc", "col"] -> collection "col" of document "doc"
//   - ["db", "doc", "col", "doc2"] -> document "doc2" in collection "col"
//
// isCollection: true if the original path ended with "/"
//
// Returns:
//   - the parent (collection or database's docs skiplist)
//   - the final component name (document/collection name at the target level)
//   - error if any intermediate node doesn't exist
func (s *Store) navigatePath(components []string) (*skiplist.SkipList[string, *Document], string, error) {
	if len(components) == 0 {
		return nil, "", fmt.Errorf("empty path")
	}

	dbName := components[0]
	db, err := s.getDatabase(dbName)
	if err != nil {
		return nil, "", fmt.Errorf("database %q: %w", dbName, ErrNotFound)
	}

	if len(components) == 1 {
		// Returns the db's top-level docs skiplist with an empty name
		// This shouldn't normally happen for a doc-level operation
		return db.docs, "", nil
	}

	// Navigate through alternating doc/collection levels
	// components[1] is a doc, components[2] is a collection, components[3] is a doc...
	currentDocs := db.docs
	for i := 1; i < len(components)-1; i++ {
		name := components[i]
		if i%2 == 1 {
			// Document level
			doc, found := currentDocs.Find(name)
			if !found {
				return nil, "", fmt.Errorf("document %q: %w", name, ErrNotFound)
			}
			// Next level is a collection
			if i+1 < len(components)-1 || i+1 == len(components)-1 {
				// continue to collection level
				i++
				colName := components[i]
				col, found := doc.collections.Find(colName)
				if !found {
					return nil, "", fmt.Errorf("collection %q: %w", colName, ErrNotFound)
				}
				currentDocs = col.docs
			}
		}
	}

	return currentDocs, components[len(components)-1], nil
}

// getOrCreateCollection gets or creates a collection on a document.
func getOrCreateCollection(doc *Document, colName string) *Collection {
	col, found := doc.collections.Find(colName)
	if !found {
		newCol := newCollection()
		doc.collections.Upsert(colName, func(k string, curr *Collection, exists bool) (*Collection, error) {
			if exists {
				return curr, nil
			}
			return newCol, nil
		})
		col, _ = doc.collections.Find(colName)
	}
	return col
}

// resolveCollectionPath navigates a path like "db/doc/col/" and returns the
// parent skiplist and the last component.
// components should NOT include trailing empty string from splitting "db/doc/col/"
func (s *Store) resolveCollectionPath(components []string) (*skiplist.SkipList[string, *Document], *Collection, error) {
	if len(components) < 2 {
		return nil, nil, fmt.Errorf("invalid collection path")
	}

	dbName := components[0]
	db, err := s.getDatabase(dbName)
	if err != nil {
		return nil, nil, fmt.Errorf("database %q: %w", dbName, ErrNotFound)
	}

	if len(components) == 2 {
		// Top-level collection = the database itself
		// "db/col/" would be components = ["db", "col"]
		// But wait, "db/" is a database collection, not "db/col/"
		// A top-level collection is just the database.
		// Actually for GET /v1/db/ we return db.docs contents
		return db.docs, nil, nil
	}

	// Navigate: db / doc / col / doc / col ...
	// The last component (even index from 2) should be a collection
	currentDocs := db.docs
	var lastCol *Collection

	for i := 1; i < len(components); i++ {
		name := components[i]
		if i%2 == 1 {
			// Document
			doc, found := currentDocs.Find(name)
			if !found {
				return nil, nil, fmt.Errorf("document %q: %w", name, ErrNotFound)
			}
			if i == len(components)-1 {
				// This is the last component, it's a document at a collection path - invalid
				return nil, nil, fmt.Errorf("expected collection, found document")
			}
			// Next is a collection name
			i++
			if i >= len(components) {
				return nil, nil, fmt.Errorf("incomplete path")
			}
			colName := components[i]
			col, found := doc.collections.Find(colName)
			if i == len(components)-1 {
				if !found {
					return nil, nil, fmt.Errorf("collection %q: %w", colName, ErrNotFound)
				}
				lastCol = col
				currentDocs = col.docs
			} else {
				if !found {
					return nil, nil, fmt.Errorf("collection %q: %w", colName, ErrNotFound)
				}
				currentDocs = col.docs
			}
		}
	}

	return currentDocs, lastCol, nil
}

// PutDocument creates or overwrites a document at the given path.
// components: parsed path components (db/doc or db/doc/col/doc2 etc.)
// overwrite: if false, fails if document already exists
// username: the authenticated user
func (s *Store) PutDocument(components []string, body []byte, username string, overwrite bool) (*DocResult, error) {
	// Validate document
	var docValue jsondata.JSONValue
	if err := json.Unmarshal(body, &docValue); err != nil {
		return nil, fmt.Errorf("invalid JSON: %w", err)
	}
	if err := s.validateDocument(docValue); err != nil {
		return nil, fmt.Errorf("schema validation failed: %w", err)
	}

	if len(components) < 2 {
		return nil, fmt.Errorf("invalid document path")
	}

	// Navigate to parent collection
	parentDocs, docName, err := s.navigateToParentCollection(components)
	if err != nil {
		return nil, err
	}

	now := time.Now().UnixMilli()
	var result *DocResult

	_, upsertErr := parentDocs.Upsert(docName, func(key string, curr *Document, exists bool) (*Document, error) {
		if exists && !overwrite {
			return nil, ErrConflict
		}

		var meta Metadata
		if exists {
			meta = Metadata{
				CreatedBy:      curr.Meta.CreatedBy,
				CreatedAt:      curr.Meta.CreatedAt,
				LastModifiedBy: username,
				LastModifiedAt: now,
			}
		} else {
			meta = Metadata{
				CreatedBy:      username,
				CreatedAt:      now,
				LastModifiedBy: username,
				LastModifiedAt: now,
			}
		}

		var newDoc *Document
		if exists {
			newDoc = curr
			newDoc.Data = docValue
			newDoc.Meta = meta
		} else {
			newDoc = &Document{
				Data:        docValue,
				Meta:        meta,
				collections: skiplist.New[string, *Collection](),
				subs:        newSubList(),
			}
		}

		result = &DocResult{
			Path: buildPath(components),
			Doc:  docValue,
			Meta: meta,
		}
		return newDoc, nil
	})

	if upsertErr != nil {
		return nil, upsertErr
	}

	// Notify subscribers after successful put
	if result != nil {
		s.notifyDocSubscribers(components, *result)
		s.notifyCollectionSubscribers(components, *result)
	}

	return result, nil
}

// GetDocument retrieves a document at the given path.
func (s *Store) GetDocument(components []string) (*DocResult, error) {
	if len(components) < 2 {
		return nil, ErrNotFound
	}

	parentDocs, docName, err := s.navigateToParentCollection(components)
	if err != nil {
		return nil, err
	}

	doc, found := parentDocs.Find(docName)
	if !found {
		return nil, ErrNotFound
	}

	return &DocResult{
		Path: buildPath(components),
		Doc:  doc.Data,
		Meta: doc.Meta,
	}, nil
}

// DeleteDocument deletes a document at the given path.
func (s *Store) DeleteDocument(components []string) error {
	if len(components) < 2 {
		return ErrNotFound
	}

	parentDocs, docName, err := s.navigateToParentCollection(components)
	if err != nil {
		return err
	}

	_, removed := parentDocs.Remove(docName)
	if !removed {
		return ErrNotFound
	}

	// Notify subscribers
	path := buildPath(components)
	s.notifyDeleteDocSubscribers(components, path)
	s.notifyDeleteCollectionSubscribers(components, path)

	return nil
}

// GetCollection returns all documents in a collection.
// components: the parsed path up to the collection (e.g., ["db"] for top-level).
// start, end: interval bounds (empty string means no bound).
func (s *Store) GetCollection(components []string, start, end string) ([]DocResult, error) {
	docs, err := s.getCollectionDocs(components)
	if err != nil {
		return nil, err
	}

	ctx := context.Background()
	pairs, err := docs.Query(ctx, start, end)
	if err != nil {
		return nil, err
	}

	var results []DocResult
	for _, p := range pairs {
		docComponents := append(append([]string{}, components...), p.Key)
		results = append(results, DocResult{
			Path: buildPath(docComponents),
			Doc:  p.Value.Data,
			Meta: p.Value.Meta,
		})
	}
	return results, nil
}

// getCollectionDocs returns the skiplist for a collection identified by components.
// components: for top-level db collection, pass ["db"]
// for nested collection, pass ["db", "doc", "col", ...]  (ending in collection name)
func (s *Store) getCollectionDocs(components []string) (*skiplist.SkipList[string, *Document], error) {
	if len(components) == 0 {
		return nil, ErrNotFound
	}

	dbName := components[0]
	db, found := s.databases.Find(dbName)
	if !found {
		return nil, ErrNotFound
	}

	if len(components) == 1 {
		// Top-level database collection
		return db.docs, nil
	}

	// Navigate: components[1] is doc, components[2] is col, etc.
	// The last component should be a collection name
	currentDocs := db.docs
	for i := 1; i < len(components); i++ {
		name := components[i]
		if i%2 == 1 {
			// Document
			doc, found := currentDocs.Find(name)
			if !found {
				return nil, ErrNotFound
			}
			if i == len(components)-1 {
				// Last component is a document - for collection queries, we need a collection
				// This should be the collection case; return the parent docs
				return currentDocs, nil
			}
		} else {
			// Collection
			// Need the previous document to get this collection
			// i-1 was the document
			prevDocName := components[i-1]
			doc, found := currentDocs.Find(prevDocName)
			if !found {
				return nil, ErrNotFound
			}
			col, found := doc.collections.Find(name)
			if !found {
				return nil, ErrNotFound
			}
			if i == len(components)-1 {
				return col.docs, nil
			}
			currentDocs = col.docs
		}
	}
	return currentDocs, nil
}

// navigateToParentCollection returns the docs skiplist for the parent collection
// and the final document name.
// e.g., for ["db", "doc1"] -> returns db.docs and "doc1"
// for ["db", "doc1", "col1", "doc2"] -> returns col1.docs and "doc2"
func (s *Store) navigateToParentCollection(components []string) (*skiplist.SkipList[string, *Document], string, error) {
	if len(components) < 2 {
		return nil, "", fmt.Errorf("invalid path")
	}

	dbName := components[0]
	db, found := s.databases.Find(dbName)
	if !found {
		return nil, "", ErrNotFound
	}

	if len(components) == 2 {
		return db.docs, components[1], nil
	}

	// Navigate through alternating doc/collection levels
	currentDocs := db.docs
	for i := 1; i < len(components)-1; {
		docName := components[i]
		doc, found := currentDocs.Find(docName)
		if !found {
			return nil, "", ErrNotFound
		}
		i++
		if i >= len(components)-1 {
			// If we've consumed all but the last component, we need to check
			// if the next one is a collection or document
			break
		}
		colName := components[i]
		col, found := doc.collections.Find(colName)
		if !found {
			return nil, "", ErrNotFound
		}
		currentDocs = col.docs
		i++
	}

	return currentDocs, components[len(components)-1], nil
}

// CreateCollection creates a collection at the given path.
// components: ends with the collection name (e.g., ["db", "doc", "col"])
func (s *Store) CreateCollection(components []string) error {
	if len(components) < 3 || len(components)%2 == 0 {
		// Collection names are at even depths from db: db/doc/col, db/doc/col/doc/col2
		// Length of components: 3 (db, doc, col), 5 (db, doc, col, doc2, col2)...
		// Actually len must be odd and >= 3
		return fmt.Errorf("invalid collection path")
	}

	dbName := components[0]
	db, found := s.databases.Find(dbName)
	if !found {
		return ErrNotFound
	}

	currentDocs := db.docs

	// Navigate to the document that owns this collection
	for i := 1; i < len(components)-1; {
		docName := components[i]
		i++
		colName := components[i]
		i++

		doc, found := currentDocs.Find(docName)
		if !found {
			return ErrNotFound
		}

		if i >= len(components) {
			// colName is the collection to create
			_, err := doc.collections.Upsert(colName, func(k string, curr *Collection, exists bool) (*Collection, error) {
				if exists {
					return nil, ErrAlreadyExists
				}
				return newCollection(), nil
			})
			return err
		}

		col, found := doc.collections.Find(colName)
		if !found {
			return ErrNotFound
		}
		currentDocs = col.docs
	}

	// Last component is the collection name, owned by the last document we navigated to
	// But we need a doc reference here
	// Let's re-navigate properly
	return s.createCollectionInner(components)
}

func (s *Store) createCollectionInner(components []string) error {
	dbName := components[0]
	db, found := s.databases.Find(dbName)
	if !found {
		return ErrNotFound
	}

	currentDocs := db.docs

	// components: db, doc1, col1, doc2, col2, ...
	// Last component is the new collection name
	// Second-to-last is its owner document
	for i := 1; i < len(components)-2; i += 2 {
		docName := components[i]
		colName := components[i+1]

		doc, found := currentDocs.Find(docName)
		if !found {
			return ErrNotFound
		}

		col, found := doc.collections.Find(colName)
		if !found {
			return ErrNotFound
		}
		currentDocs = col.docs
	}

	// Now currentDocs is the collection that owns the second-to-last component
	// The second-to-last is a document, the last is the new collection name
	ownerDocName := components[len(components)-2]
	newColName := components[len(components)-1]

	doc, found := currentDocs.Find(ownerDocName)
	if !found {
		return ErrNotFound
	}

	_, err := doc.collections.Upsert(newColName, func(k string, curr *Collection, exists bool) (*Collection, error) {
		if exists {
			return nil, ErrAlreadyExists
		}
		return newCollection(), nil
	})
	return err
}

// DeleteCollection deletes a collection at the given path.
func (s *Store) DeleteCollection(components []string) error {
	if len(components) < 3 {
		return fmt.Errorf("invalid collection path")
	}

	dbName := components[0]
	db, found := s.databases.Find(dbName)
	if !found {
		return ErrNotFound
	}

	currentDocs := db.docs

	for i := 1; i < len(components)-2; i += 2 {
		docName := components[i]
		colName := components[i+1]

		doc, found := currentDocs.Find(docName)
		if !found {
			return ErrNotFound
		}
		col, found := doc.collections.Find(colName)
		if !found {
			return ErrNotFound
		}
		currentDocs = col.docs
	}

	ownerDocName := components[len(components)-2]
	colName := components[len(components)-1]

	doc, found := currentDocs.Find(ownerDocName)
	if !found {
		return ErrNotFound
	}

	_, removed := doc.collections.Remove(colName)
	if !removed {
		return ErrNotFound
	}

	// Notify collection subscribers
	path := buildCollectionPath(components)
	s.notifyCollectionDeleted(components, path)

	return nil
}

// PostDocument creates a document with a random name in the given collection.
// collectionComponents: the collection path (e.g., ["db"] for top-level)
func (s *Store) PostDocument(collectionComponents []string, body []byte, username string) (*DocResult, error) {
	var docValue jsondata.JSONValue
	if err := json.Unmarshal(body, &docValue); err != nil {
		return nil, fmt.Errorf("invalid JSON: %w", err)
	}
	if err := s.validateDocument(docValue); err != nil {
		return nil, fmt.Errorf("schema validation failed: %w", err)
	}

	docs, err := s.getCollectionDocs(collectionComponents)
	if err != nil {
		return nil, err
	}

	// Generate unique name
	name := generateRandomName()
	for {
		_, found := docs.Find(name)
		if !found {
			break
		}
		name = generateRandomName()
	}

	now := time.Now().UnixMilli()
	meta := Metadata{
		CreatedBy:      username,
		CreatedAt:      now,
		LastModifiedBy: username,
		LastModifiedAt: now,
	}

	newDoc := &Document{
		Data:        docValue,
		Meta:        meta,
		collections: skiplist.New[string, *Collection](),
		subs:        newSubList(),
	}

	docComponents := append(append([]string{}, collectionComponents...), name)

	_, err = docs.Upsert(name, func(k string, curr *Document, exists bool) (*Document, error) {
		return newDoc, nil
	})
	if err != nil {
		return nil, err
	}

	result := &DocResult{
		Path: buildPath(docComponents),
		Doc:  docValue,
		Meta: meta,
	}

	s.notifyCollectionSubscribers(docComponents, *result)

	return result, nil
}

// PatchDocument applies a list of patch operations to a document.
// Returns the patch result (uri, patchFailed, message).
type PatchOp struct {
	Op    string            `json:"op"`
	Path  string            `json:"path"`
	Value jsondata.JSONValue `json:"value"`
}

type PatchResult struct {
	URI         string `json:"uri"`
	PatchFailed bool   `json:"patchFailed"`
	Message     string `json:"message"`
}

func (s *Store) PatchDocument(components []string, patches []PatchOp, username string) (*PatchResult, error) {
	if len(components) < 2 {
		return nil, ErrNotFound
	}

	parentDocs, docName, err := s.navigateToParentCollection(components)
	if err != nil {
		return nil, err
	}

	docPath := buildPath(components)
	result := &PatchResult{URI: docPath}

	var updatedDoc *Document
	var updatedResult *DocResult

	_, upsertErr := parentDocs.Upsert(docName, func(key string, curr *Document, exists bool) (*Document, error) {
		if !exists {
			return nil, ErrNotFound
		}

		// Apply patches
		newData, patchErr := applyPatches(curr.Data, patches)
		if patchErr != nil {
			result.PatchFailed = true
			result.Message = patchErr.Error()
			// Return current value unchanged
			return curr, nil
		}

		// Validate patched document
		if err := s.validateDocument(newData); err != nil {
			result.PatchFailed = true
			result.Message = fmt.Sprintf("schema validation failed: %s", err.Error())
			return curr, nil
		}

		now := time.Now().UnixMilli()
		curr.Data = newData
		curr.Meta.LastModifiedBy = username
		curr.Meta.LastModifiedAt = now
		result.PatchFailed = false
		result.Message = "patches applied"
		updatedDoc = curr
		updatedResult = &DocResult{
			Path: docPath,
			Doc:  newData,
			Meta: curr.Meta,
		}
		return curr, nil
	})

	if upsertErr != nil {
		return nil, upsertErr
	}

	// Notify subscribers if patch succeeded
	if updatedDoc != nil && updatedResult != nil && !result.PatchFailed {
		s.notifyDocSubscribers(components, *updatedResult)
		s.notifyCollectionSubscribers(components, *updatedResult)
	}

	return result, nil
}

// generateRandomName generates a random document name.
func generateRandomName() string {
	const chars = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ0123456789"
	b := make([]byte, 14)
	for i := range b {
		b[i] = chars[rand.Intn(len(chars))]
	}
	return string(b)
}

// buildPath builds a /v1/db/doc/col/doc2 style path from components.
func buildPath(components []string) string {
	if len(components) == 0 {
		return "/v1/"
	}
	return "/v1/" + joinComponents(components)
}

// buildCollectionPath builds a path for a collection (ends with /).
func buildCollectionPath(components []string) string {
	return buildPath(components) + "/"
}

func joinComponents(components []string) string {
	result := ""
	for i, c := range components {
		if i > 0 {
			result += "/"
		}
		result += c
	}
	return result
}

// SubscribeDocument adds a subscriber channel for a specific document.
// Returns the channel and a cleanup function.
func (s *Store) SubscribeDocument(components []string) (chan Event, func(), *DocResult, error) {
	parentDocs, docName, err := s.navigateToParentCollection(components)
	if err != nil {
		return nil, nil, nil, err
	}

	doc, found := parentDocs.Find(docName)
	if !found {
		return nil, nil, nil, ErrNotFound
	}

	ch := make(chan Event, 100)
	doc.subs.add(ch)

	cleanup := func() {
		doc.subs.remove(ch)
	}

	currentDoc := &DocResult{
		Path: buildPath(components),
		Doc:  doc.Data,
		Meta: doc.Meta,
	}

	return ch, cleanup, currentDoc, nil
}

// SubscribeCollection subscribes to a collection.
// Returns the channel, cleanup func, and initial documents.
func (s *Store) SubscribeCollection(components []string, start, end string) (chan Event, func(), []DocResult, error) {
	docs, col, err := s.getCollectionForSubscription(components)
	if err != nil {
		return nil, nil, nil, err
	}

	ch := make(chan Event, 100)
	if col != nil {
		col.subs.add(ch)
	} else {
		// Top-level db collection - need to get db subs
		db, dbErr := s.getDatabase(components[0])
		if dbErr != nil {
			return nil, nil, nil, dbErr
		}
		db.subs.add(ch)
	}

	ctx := context.Background()
	pairs, queryErr := docs.Query(ctx, start, end)
	if queryErr != nil {
		return nil, nil, nil, queryErr
	}

	var initial []DocResult
	for _, p := range pairs {
		docComponents := append(append([]string{}, components...), p.Key)
		initial = append(initial, DocResult{
			Path: buildPath(docComponents),
			Doc:  p.Value.Data,
			Meta: p.Value.Meta,
		})
	}

	cleanup := func() {
		if col != nil {
			col.subs.remove(ch)
		} else {
			db, dbErr := s.getDatabase(components[0])
			if dbErr == nil {
				db.subs.remove(ch)
			}
		}
	}

	return ch, cleanup, initial, nil
}

// getCollectionForSubscription returns the docs skiplist and collection for subscription.
func (s *Store) getCollectionForSubscription(components []string) (*skiplist.SkipList[string, *Document], *Collection, error) {
	if len(components) == 0 {
		return nil, nil, ErrNotFound
	}

	dbName := components[0]
	db, found := s.databases.Find(dbName)
	if !found {
		return nil, nil, ErrNotFound
	}

	if len(components) == 1 {
		return db.docs, nil, nil
	}

	currentDocs := db.docs
	var lastCol *Collection

	for i := 1; i < len(components); i++ {
		name := components[i]
		if i%2 == 1 {
			// Document
			doc, found := currentDocs.Find(name)
			if !found {
				return nil, nil, ErrNotFound
			}
			if i == len(components)-1 {
				// Shouldn't happen for collection subscription
				return currentDocs, nil, nil
			}
			i++
			colName := components[i]
			col, found := doc.collections.Find(colName)
			if !found {
				return nil, nil, ErrNotFound
			}
			lastCol = col
			currentDocs = col.docs
		}
	}

	return currentDocs, lastCol, nil
}

// notifyDocSubscribers notifies subscribers of a document update.
func (s *Store) notifyDocSubscribers(components []string, result DocResult) {
	if len(components) < 2 {
		return
	}
	parentDocs, docName, err := s.navigateToParentCollection(components)
	if err != nil {
		return
	}
	doc, found := parentDocs.Find(docName)
	if !found {
		return
	}
	doc.subs.broadcast(Event{
		Type: "update",
		Path: result.Path,
		Doc:  &result,
	})
}

// notifyCollectionSubscribers notifies the parent collection's subscribers.
func (s *Store) notifyCollectionSubscribers(docComponents []string, result DocResult) {
	if len(docComponents) < 2 {
		return
	}
	// The parent collection's components are everything except the last element
	collectionComponents := docComponents[:len(docComponents)-1]
	s.broadcastToCollectionSubs(collectionComponents, Event{
		Type: "update",
		Path: result.Path,
		Doc:  &result,
	})
}

// notifyDeleteDocSubscribers notifies document subscribers of deletion.
func (s *Store) notifyDeleteDocSubscribers(components []string, path string) {
	// Note: document is already removed from the skiplist, so we can't find it
	// Just broadcast delete event to any remaining subscribers
}

// notifyDeleteCollectionSubscribers notifies the parent collection subscribers of deletion.
func (s *Store) notifyDeleteCollectionSubscribers(docComponents []string, path string) {
	if len(docComponents) < 2 {
		return
	}
	collectionComponents := docComponents[:len(docComponents)-1]
	s.broadcastToCollectionSubs(collectionComponents, Event{
		Type: "delete",
		Path: path,
		Doc:  nil,
	})
}

// notifyCollectionDeleted notifies collection subscribers that the collection was deleted.
func (s *Store) notifyCollectionDeleted(components []string, path string) {
	s.broadcastToCollectionSubs(components, Event{
		Type: "delete",
		Path: path,
		Doc:  nil,
	})
}

// broadcastToCollectionSubs broadcasts an event to a collection's subscribers.
func (s *Store) broadcastToCollectionSubs(components []string, event Event) {
	if len(components) == 0 {
		return
	}
	if len(components) == 1 {
		db, found := s.databases.Find(components[0])
		if !found {
			return
		}
		db.subs.broadcast(event)
		return
	}

	dbName := components[0]
	db, found := s.databases.Find(dbName)
	if !found {
		return
	}

	currentDocs := db.docs
	for i := 1; i < len(components); i++ {
		name := components[i]
		if i%2 == 1 {
			// Document
			doc, found := currentDocs.Find(name)
			if !found {
				return
			}
			if i == len(components)-1 {
				// This is the last component - it's a document, not a collection
				return
			}
			i++
			colName := components[i]
			col, found := doc.collections.Find(colName)
			if !found {
				return
			}
			if i == len(components)-1 {
				col.subs.broadcast(event)
				return
			}
			currentDocs = col.docs
		}
	}
}

// Package store - patch operations for documents.
// Implements ArrayAdd, ArrayRemove, and ObjectAdd patch operations.
package store

import (
	"encoding/json"
	"fmt"
	"strings"

	"github.com/RICE-COMP318-FALL24/owldb-p1/jsondata"
)

// applyPatches applies a list of patch operations to a JSON value.
// If any operation fails, the original value is returned unchanged.
func applyPatches(value jsondata.JSONValue, patches []PatchOp) (jsondata.JSONValue, error) {
	if len(patches) == 0 {
		return value, nil
	}

	// Work on a mutable map representation
	// We unmarshal to a nested map structure, apply ops, then re-marshal
	rawBytes, err := json.Marshal(value)
	if err != nil {
		return value, fmt.Errorf("failed to serialize document: %w", err)
	}

	var root interface{}
	if err := json.Unmarshal(rawBytes, &root); err != nil {
		return value, fmt.Errorf("failed to deserialize document: %w", err)
	}

	for _, patch := range patches {
		switch patch.Op {
		case "ArrayAdd":
			root, err = applyArrayAdd(root, patch.Path, patch.Value)
		case "ArrayRemove":
			root, err = applyArrayRemove(root, patch.Path, patch.Value)
		case "ObjectAdd":
			root, err = applyObjectAdd(root, patch.Path, patch.Value)
		default:
			return value, fmt.Errorf("unknown patch operation: %s", patch.Op)
		}
		if err != nil {
			return value, err
		}
	}

	// Re-marshal and unmarshal into JSONValue
	resultBytes, err := json.Marshal(root)
	if err != nil {
		return value, fmt.Errorf("failed to serialize patched document: %w", err)
	}

	var result jsondata.JSONValue
	if err := json.Unmarshal(resultBytes, &result); err != nil {
		return value, fmt.Errorf("failed to deserialize patched document: %w", err)
	}

	return result, nil
}

// parseJSONPointer parses a JSON Pointer (RFC 6901) into path components.
// e.g., "/a/b/c" -> ["a", "b", "c"]
func parseJSONPointer(pointer string) ([]string, error) {
	if pointer == "" {
		return []string{}, nil
	}
	if !strings.HasPrefix(pointer, "/") {
		return nil, fmt.Errorf("invalid JSON pointer: must start with /")
	}
	parts := strings.Split(pointer[1:], "/")
	for i, part := range parts {
		// Unescape ~1 -> / and ~0 -> ~
		part = strings.ReplaceAll(part, "~1", "/")
		part = strings.ReplaceAll(part, "~0", "~")
		parts[i] = part
	}
	return parts, nil
}

// navigateToTarget navigates to the element at the given JSON pointer path.
// Returns the element at that path.
func navigateToTarget(root interface{}, parts []string) (interface{}, error) {
	current := root
	for _, part := range parts {
		switch v := current.(type) {
		case map[string]interface{}:
			val, ok := v[part]
			if !ok {
				return nil, fmt.Errorf("path element %q not found", part)
			}
			current = val
		case []interface{}:
			// JSON pointer into arrays uses numeric indices
			idx := 0
			if _, err := fmt.Sscanf(part, "%d", &idx); err != nil {
				return nil, fmt.Errorf("non-numeric array index: %q", part)
			}
			if idx < 0 || idx >= len(v) {
				return nil, fmt.Errorf("array index %d out of bounds", idx)
			}
			current = v[idx]
		default:
			return nil, fmt.Errorf("cannot navigate into %T at path element %q", current, part)
		}
	}
	return current, nil
}

// navigateToParent navigates to the parent element (all but last path component)
// and returns the parent and the final key.
func navigateToParent(root interface{}, parts []string) (interface{}, string, error) {
	if len(parts) == 0 {
		return nil, "", fmt.Errorf("empty path")
	}
	parentParts := parts[:len(parts)-1]
	lastKey := parts[len(parts)-1]
	parent, err := navigateToTarget(root, parentParts)
	if err != nil {
		return nil, "", err
	}
	return parent, lastKey, nil
}

// applyArrayAdd adds a value to an array at the given JSON pointer path
// (if not already present).
func applyArrayAdd(root interface{}, pointer string, value jsondata.JSONValue) (interface{}, error) {
	parts, err := parseJSONPointer(pointer)
	if err != nil {
		return nil, err
	}

	target, err := navigateToTarget(root, parts)
	if err != nil {
		return nil, fmt.Errorf("ArrayAdd: %w", err)
	}

	arr, ok := target.([]interface{})
	if !ok {
		return nil, fmt.Errorf("ArrayAdd: path %q does not refer to an array", pointer)
	}

	// Get the raw value to compare
	rawVal, err := json.Marshal(value)
	if err != nil {
		return nil, fmt.Errorf("ArrayAdd: failed to serialize value: %w", err)
	}
	var newVal interface{}
	if err := json.Unmarshal(rawVal, &newVal); err != nil {
		return nil, fmt.Errorf("ArrayAdd: failed to deserialize value: %w", err)
	}

	// Check if already present
	for _, existing := range arr {
		existingBytes, _ := json.Marshal(existing)
		if string(existingBytes) == string(rawVal) {
			// Already present, no-op
			return root, nil
		}
	}

	// Add to array
	newArr := append(arr, newVal)

	// Update the root with the new array
	return setAtPath(root, parts, newArr)
}

// applyArrayRemove removes a value from an array at the given JSON pointer path.
func applyArrayRemove(root interface{}, pointer string, value jsondata.JSONValue) (interface{}, error) {
	parts, err := parseJSONPointer(pointer)
	if err != nil {
		return nil, err
	}

	target, err := navigateToTarget(root, parts)
	if err != nil {
		return nil, fmt.Errorf("ArrayRemove: %w", err)
	}

	arr, ok := target.([]interface{})
	if !ok {
		return nil, fmt.Errorf("ArrayRemove: path %q does not refer to an array", pointer)
	}

	rawVal, err := json.Marshal(value)
	if err != nil {
		return nil, fmt.Errorf("ArrayRemove: failed to serialize value: %w", err)
	}

	// Remove matching elements
	newArr := make([]interface{}, 0, len(arr))
	for _, existing := range arr {
		existingBytes, _ := json.Marshal(existing)
		if string(existingBytes) != string(rawVal) {
			newArr = append(newArr, existing)
		}
	}

	return setAtPath(root, parts, newArr)
}

// applyObjectAdd adds a key-value pair to an object at the given JSON pointer path
// (if key does not already exist).
func applyObjectAdd(root interface{}, pointer string, value jsondata.JSONValue) (interface{}, error) {
	parts, err := parseJSONPointer(pointer)
	if err != nil {
		return nil, err
	}
	if len(parts) == 0 {
		return nil, fmt.Errorf("ObjectAdd: path cannot be empty")
	}

	parent, lastKey, err := navigateToParent(root, parts)
	if err != nil {
		return nil, fmt.Errorf("ObjectAdd: %w", err)
	}

	obj, ok := parent.(map[string]interface{})
	if !ok {
		return nil, fmt.Errorf("ObjectAdd: parent at path %q is not an object", strings.Join(parts[:len(parts)-1], "/"))
	}

	// Only add if key doesn't exist
	if _, exists := obj[lastKey]; exists {
		return root, nil
	}

	rawVal, err := json.Marshal(value)
	if err != nil {
		return nil, fmt.Errorf("ObjectAdd: failed to serialize value: %w", err)
	}
	var newVal interface{}
	if err := json.Unmarshal(rawVal, &newVal); err != nil {
		return nil, fmt.Errorf("ObjectAdd: failed to deserialize value: %w", err)
	}

	obj[lastKey] = newVal
	return root, nil
}

// setAtPath sets the value at the given JSON pointer path.
func setAtPath(root interface{}, parts []string, newVal interface{}) (interface{}, error) {
	if len(parts) == 0 {
		return newVal, nil
	}

	switch v := root.(type) {
	case map[string]interface{}:
		key := parts[0]
		if len(parts) == 1 {
			v[key] = newVal
			return v, nil
		}
		child, ok := v[key]
		if !ok {
			return nil, fmt.Errorf("path element %q not found", key)
		}
		newChild, err := setAtPath(child, parts[1:], newVal)
		if err != nil {
			return nil, err
		}
		v[key] = newChild
		return v, nil
	case []interface{}:
		idx := 0
		if _, err := fmt.Sscanf(parts[0], "%d", &idx); err != nil {
			return nil, fmt.Errorf("non-numeric array index: %q", parts[0])
		}
		if idx < 0 || idx >= len(v) {
			return nil, fmt.Errorf("array index %d out of bounds", idx)
		}
		if len(parts) == 1 {
			v[idx] = newVal
			return v, nil
		}
		newChild, err := setAtPath(v[idx], parts[1:], newVal)
		if err != nil {
			return nil, err
		}
		v[idx] = newChild
		return v, nil
	default:
		return nil, fmt.Errorf("cannot set path in %T", root)
	}
}

// Package handler implements HTTP handlers for the OwlDB REST API.
package handler

import (
	"encoding/json"
	"errors"
	"fmt"
	"log/slog"
	"net/http"
	"strings"
	"time"

	"github.com/RICE-COMP318-FALL24/owldb-p1/auth"
	"github.com/RICE-COMP318-FALL24/owldb-p1/store"
)

// Handler implements the HTTP handler for the OwlDB API.
type Handler struct {
	store *store.Store
	auth  *auth.Store
}

// New creates a new Handler.
func New(s *store.Store, a *auth.Store) *Handler {
	return &Handler{store: s, auth: a}
}

// writeJSON writes a JSON response with the given status code.
func writeJSON(w http.ResponseWriter, status int, body interface{}) {
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(status)
	if body != nil {
		json.NewEncoder(w).Encode(body)
	}
}

// writeError writes a JSON error response.
func writeError(w http.ResponseWriter, status int, msg string) {
	writeJSON(w, status, msg)
}

// requireAuth checks the Authorization header and returns the username.
// Returns false and writes a 401 response if auth fails.
func (h *Handler) requireAuth(w http.ResponseWriter, r *http.Request) (string, bool) {
	token := auth.ExtractToken(r)
	if token == "" {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return "", false
	}
	username, valid := h.auth.Validate(token)
	if !valid {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return "", false
	}
	return username, true
}

// parsePath splits a URL path after /v1/ into components.
// Returns components and whether the path ended with "/" (collection indicator).
func parsePath(urlPath string) (components []string, isCollection bool) {
	// Strip /v1/ prefix
	path := strings.TrimPrefix(urlPath, "/v1")
	path = strings.TrimPrefix(path, "/")

	isCollection = strings.HasSuffix(path, "/")
	path = strings.TrimSuffix(path, "/")

	if path == "" {
		return nil, isCollection
	}

	components = strings.Split(path, "/")
	return components, isCollection
}

// parseInterval parses an interval query parameter like "[low,high]".
// Returns low, high strings (empty string means no bound).
func parseInterval(interval string) (string, string, error) {
	if interval == "" {
		return "", "", nil
	}
	// Format: [low,high] or [low,] or [,high] or [,]
	if !strings.HasPrefix(interval, "[") || !strings.HasSuffix(interval, "]") {
		return "", "", fmt.Errorf("invalid interval format: %q", interval)
	}
	inner := interval[1 : len(interval)-1]
	parts := strings.SplitN(inner, ",", 2)
	if len(parts) != 2 {
		return "", "", fmt.Errorf("invalid interval format: %q", interval)
	}
	return parts[0], parts[1], nil
}

// setCORSHeaders sets CORS headers for cross-origin requests.
func setCORSHeaders(w http.ResponseWriter) {
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.Header().Set("Access-Control-Allow-Methods", "GET, PUT, POST, PATCH, DELETE, OPTIONS")
	w.Header().Set("Access-Control-Allow-Headers", "Authorization, Content-Type")
}

// ServeHTTP is the main dispatcher.
func (h *Handler) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	slog.Debug("Request", "method", r.Method, "path", r.URL.Path, "query", r.URL.RawQuery)

	setCORSHeaders(w)

	// Route based on path prefix
	switch {
	case r.URL.Path == "/auth" || r.URL.Path == "/auth/":
		h.handleAuth(w, r)
	case strings.HasPrefix(r.URL.Path, "/v1/"):
		h.handleV1(w, r)
	case r.URL.Path == "/v1":
		// GET /v1 - list databases or handle OPTIONS
		if r.Method == http.MethodOptions {
			h.handleOptions(w, r, nil, false)
			return
		}
		writeError(w, http.StatusNotFound, "not found")
	default:
		writeError(w, http.StatusNotFound, "not found")
	}
}

// handleAuth handles POST /auth (login) and DELETE /auth (logout).
func (h *Handler) handleAuth(w http.ResponseWriter, r *http.Request) {
	switch r.Method {
	case http.MethodOptions:
		w.Header().Set("Allow", "POST, DELETE, OPTIONS")
		w.WriteHeader(http.StatusNoContent)
	case http.MethodPost:
		h.handleLogin(w, r)
	case http.MethodDelete:
		h.handleLogout(w, r)
	default:
		writeError(w, http.StatusMethodNotAllowed, "method not allowed")
	}
}

func (h *Handler) handleLogin(w http.ResponseWriter, r *http.Request) {
	var body struct {
		Username string `json:"username"`
	}
	if err := json.NewDecoder(r.Body).Decode(&body); err != nil || body.Username == "" {
		writeError(w, http.StatusBadRequest, "No username in request body")
		return
	}
	token := h.auth.Login(body.Username)
	writeJSON(w, http.StatusOK, map[string]string{"token": token})
}

func (h *Handler) handleLogout(w http.ResponseWriter, r *http.Request) {
	token := auth.ExtractToken(r)
	if token == "" || !h.auth.Logout(token) {
		writeError(w, http.StatusUnauthorized, "Missing or invalid bearer token")
		return
	}
	w.WriteHeader(http.StatusNoContent)
}

// handleV1 handles all /v1/... requests.
func (h *Handler) handleV1(w http.ResponseWriter, r *http.Request) {
	if r.Method == http.MethodOptions {
		components, isCollection := parsePath(r.URL.Path)
		h.handleOptions(w, r, components, isCollection)
		return
	}

	// All non-OPTIONS requests require auth
	username, ok := h.requireAuth(w, r)
	if !ok {
		return
	}

	components, isCollection := parsePath(r.URL.Path)
	slog.Debug("Parsed path", "components", components, "isCollection", isCollection)

	if len(components) == 0 {
		// /v1/ with no further components - maybe list all databases?
		writeError(w, http.StatusNotFound, "not found")
		return
	}

	if len(components) == 1 {
		// Database-level operations
		h.handleDatabase(w, r, components[0], username)
		return
	}

	// Deeper paths
	if isCollection {
		h.handleCollection(w, r, components, username)
	} else {
		h.handleDocument(w, r, components, username)
	}
}

// handleDatabase handles PUT and DELETE on /v1/{database}[/].
func (h *Handler) handleDatabase(w http.ResponseWriter, r *http.Request, dbName string, username string) {
	switch r.Method {
	case http.MethodPut:
		err := h.store.CreateDatabase(dbName)
		if err != nil {
			if errors.Is(err, store.ErrAlreadyExists) {
				writeError(w, http.StatusConflict, fmt.Sprintf("Database %q already exists", dbName))
				return
			}
			writeError(w, http.StatusInternalServerError, err.Error())
			return
		}
		uri := "/v1/" + dbName + "/"
		w.Header().Set("Location", uri)
		writeJSON(w, http.StatusCreated, map[string]string{"uri": uri})

	case http.MethodDelete:
		err := h.store.DeleteDatabase(dbName)
		if err != nil {
			if errors.Is(err, store.ErrNotFound) {
				writeError(w, http.StatusNotFound, fmt.Sprintf("Database %q does not exist", dbName))
				return
			}
			writeError(w, http.StatusInternalServerError, err.Error())
			return
		}
		w.WriteHeader(http.StatusNoContent)

	case http.MethodGet:
		// GET /v1/{db} (no trailing slash) - treat as GET /v1/{db}/ for the collection
		h.handleCollectionGet(w, r, []string{dbName}, username)

	default:
		writeError(w, http.StatusMethodNotAllowed, "method not allowed")
	}
}

// handleCollection handles operations on collections (paths ending with /).
func (h *Handler) handleCollection(w http.ResponseWriter, r *http.Request, components []string, username string) {
	switch r.Method {
	case http.MethodGet:
		h.handleCollectionGet(w, r, components, username)
	case http.MethodPut:
		h.handleCollectionPut(w, r, components, username)
	case http.MethodPost:
		h.handleCollectionPost(w, r, components, username)
	case http.MethodDelete:
		h.handleCollectionDelete(w, r, components, username)
	default:
		writeError(w, http.StatusMethodNotAllowed, "method not allowed")
	}
}

// handleCollectionGet handles GET on a collection (with optional interval and mode=subscribe).
func (h *Handler) handleCollectionGet(w http.ResponseWriter, r *http.Request, components []string, username string) {
	mode := r.URL.Query().Get("mode")
	if mode == "subscribe" {
		h.handleCollectionSubscribe(w, r, components, username)
		return
	}

	intervalParam := r.URL.Query().Get("interval")
	start, end, err := parseInterval(intervalParam)
	if err != nil {
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	results, err := h.store.GetCollection(components, start, end)
	if err != nil {
		if errors.Is(err, store.ErrNotFound) {
			if len(components) == 1 {
				writeError(w, http.StatusNotFound, fmt.Sprintf("Database %q does not exist", components[0]))
			} else {
				writeError(w, http.StatusNotFound, "Collection does not exist")
			}
			return
		}
		writeError(w, http.StatusInternalServerError, err.Error())
		return
	}

	if results == nil {
		results = []store.DocResult{}
	}
	writeJSON(w, http.StatusOK, results)
}

// handleCollectionPut handles PUT on a collection path.
// If it's a database-level collection (len==1), create database.
// If nested (len>=3, odd), create collection.
func (h *Handler) handleCollectionPut(w http.ResponseWriter, r *http.Request, components []string, username string) {
	if len(components) == 1 {
		// Creating a database
		h.handleDatabase(w, &http.Request{Method: http.MethodPut}, components[0], username)
		return
	}

	// Creating a nested collection: len must be odd (db/doc/col, db/doc/col/doc/col2...)
	if len(components) < 3 || len(components)%2 == 0 {
		writeError(w, http.StatusBadRequest, "invalid collection path")
		return
	}

	err := h.store.CreateCollection(components)
	if err != nil {
		if errors.Is(err, store.ErrNotFound) {
			writeError(w, http.StatusNotFound, "parent resource not found")
			return
		}
		if errors.Is(err, store.ErrAlreadyExists) {
			writeError(w, http.StatusConflict, "collection already exists")
			return
		}
		writeError(w, http.StatusInternalServerError, err.Error())
		return
	}
	uri := "/v1/" + joinComponents(components) + "/"
	w.Header().Set("Location", uri)
	writeJSON(w, http.StatusCreated, map[string]string{"uri": uri})
}

// handleCollectionPost handles POST to create a document with a server-generated name.
func (h *Handler) handleCollectionPost(w http.ResponseWriter, r *http.Request, components []string, username string) {
	body, err := readBody(r)
	if err != nil {
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	result, err := h.store.PostDocument(components, body, username)
	if err != nil {
		if errors.Is(err, store.ErrNotFound) {
			writeError(w, http.StatusNotFound, "collection does not exist")
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	w.Header().Set("Location", result.Path)
	writeJSON(w, http.StatusCreated, map[string]string{"uri": result.Path})
}

// handleCollectionDelete handles DELETE on a collection.
func (h *Handler) handleCollectionDelete(w http.ResponseWriter, r *http.Request, components []string, username string) {
	if len(components) == 1 {
		// Delete database
		h.handleDatabase(w, &http.Request{Method: http.MethodDelete}, components[0], username)
		return
	}

	if len(components) < 3 || len(components)%2 == 0 {
		writeError(w, http.StatusBadRequest, "invalid collection path")
		return
	}

	err := h.store.DeleteCollection(components)
	if err != nil {
		if errors.Is(err, store.ErrNotFound) {
			writeError(w, http.StatusNotFound, "collection not found")
			return
		}
		writeError(w, http.StatusInternalServerError, err.Error())
		return
	}
	w.WriteHeader(http.StatusNoContent)
}

// handleDocument handles operations on documents (paths not ending with /).
func (h *Handler) handleDocument(w http.ResponseWriter, r *http.Request, components []string, username string) {
	switch r.Method {
	case http.MethodGet:
		mode := r.URL.Query().Get("mode")
		if mode == "subscribe" {
			h.handleDocumentSubscribe(w, r, components, username)
			return
		}
		h.handleDocumentGet(w, r, components, username)
	case http.MethodPut:
		h.handleDocumentPut(w, r, components, username)
	case http.MethodDelete:
		h.handleDocumentDelete(w, r, components, username)
	case http.MethodPatch:
		h.handleDocumentPatch(w, r, components, username)
	default:
		writeError(w, http.StatusMethodNotAllowed, "method not allowed")
	}
}

// handleDocumentGet handles GET on a document.
func (h *Handler) handleDocumentGet(w http.ResponseWriter, r *http.Request, components []string, username string) {
	result, err := h.store.GetDocument(components)
	if err != nil {
		if errors.Is(err, store.ErrNotFound) {
			writeError(w, http.StatusNotFound, "Document does not exist")
			return
		}
		writeError(w, http.StatusInternalServerError, err.Error())
		return
	}
	writeJSON(w, http.StatusOK, result)
}

// handleDocumentPut handles PUT on a document.
func (h *Handler) handleDocumentPut(w http.ResponseWriter, r *http.Request, components []string, username string) {
	mode := r.URL.Query().Get("mode")
	overwrite := true
	if mode == "nooverwrite" {
		overwrite = false
	}

	body, err := readBody(r)
	if err != nil {
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	result, err := h.store.PutDocument(components, body, username, overwrite)
	if err != nil {
		if errors.Is(err, store.ErrConflict) {
			writeError(w, http.StatusConflict, "Document already exists")
			return
		}
		if errors.Is(err, store.ErrNotFound) {
			writeError(w, http.StatusNotFound, "parent resource not found")
			return
		}
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	w.Header().Set("Location", result.Path)

	// Return 201 if created, 200 if overwritten
	// Simplified: always return 201 for new, 200 for overwrite
	writeJSON(w, http.StatusCreated, map[string]string{"uri": result.Path})
}

// handleDocumentDelete handles DELETE on a document.
func (h *Handler) handleDocumentDelete(w http.ResponseWriter, r *http.Request, components []string, username string) {
	err := h.store.DeleteDocument(components)
	if err != nil {
		if errors.Is(err, store.ErrNotFound) {
			writeError(w, http.StatusNotFound, "Document does not exist")
			return
		}
		writeError(w, http.StatusInternalServerError, err.Error())
