// handleDocumentPatch handles PATCH on a document.
func (h *Handler) handleDocumentPatch(w http.ResponseWriter, r *http.Request, components []string, username string) {
	body, err := readBody(r)
	if err != nil {
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	var patches []store.PatchOp
	if err := json.Unmarshal(body, &patches); err != nil {
		writeError(w, http.StatusBadRequest, fmt.Sprintf("invalid patch body: %s", err.Error()))
		return
	}

	result, err := h.store.PatchDocument(components, patches, username)
	if err != nil {
		if errors.Is(err, store.ErrNotFound) {
			writeError(w, http.StatusNotFound, "Document does not exist")
			return
		}
		writeError(w, http.StatusInternalServerError, err.Error())
		return
	}

	w.Header().Set("Location", result.URI)
	writeJSON(w, http.StatusOK, result)
}

// handleOptions handles OPTIONS requests.
func (h *Handler) handleOptions(w http.ResponseWriter, r *http.Request, components []string, isCollection bool) {
	var allow string
	if len(components) == 0 || isCollection {
		// Collection or database: GET, PUT, POST, DELETE, OPTIONS
		allow = "GET, PUT, POST, DELETE, OPTIONS"
	} else {
		// Document: GET, PUT, DELETE, PATCH, OPTIONS
		allow = "GET, PUT, DELETE, PATCH, OPTIONS"
	}
	w.Header().Set("Allow", allow)
	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusNoContent)
}

// handleDocumentSubscribe handles GET /v1/.../doc?mode=subscribe.
func (h *Handler) handleDocumentSubscribe(w http.ResponseWriter, r *http.Request, components []string, username string) {
	ch, cleanup, currentDoc, err := h.store.SubscribeDocument(components)
	if err != nil {
		if errors.Is(err, store.ErrNotFound) {
			writeError(w, http.StatusNotFound, "Document does not exist")
			return
		}
		writeError(w, http.StatusInternalServerError, err.Error())
		return
	}
	defer cleanup()

	// Set SSE headers
	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.WriteHeader(http.StatusOK)

	flusher, ok := w.(http.Flusher)
	if !ok {
		return
	}

	// Send current document as initial update event
	sendSSEUpdate(w, flusher, currentDoc)

	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-r.Context().Done():
			return
		case event, open := <-ch:
			if !open {
				return
			}
			if event.Type == "update" && event.Doc != nil {
				sendSSEUpdate(w, flusher, event.Doc)
			} else if event.Type == "delete" {
				sendSSEDelete(w, flusher, event.Path)
				return
			}
		case <-ticker.C:
			fmt.Fprintf(w, ": keepalive\n\n")
			flusher.Flush()
		}
	}
}

// handleCollectionSubscribe handles GET /v1/.../col/?mode=subscribe.
func (h *Handler) handleCollectionSubscribe(w http.ResponseWriter, r *http.Request, components []string, username string) {
	intervalParam := r.URL.Query().Get("interval")
	start, end, err := parseInterval(intervalParam)
	if err != nil {
		writeError(w, http.StatusBadRequest, err.Error())
		return
	}

	ch, cleanup, initial, err := h.store.SubscribeCollection(components, start, end)
	if err != nil {
		if errors.Is(err, store.ErrNotFound) {
			writeError(w, http.StatusNotFound, "Collection does not exist")
			return
		}
		writeError(w, http.StatusInternalServerError, err.Error())
		return
	}
	defer cleanup()

	w.Header().Set("Content-Type", "text/event-stream")
	w.Header().Set("Cache-Control", "no-cache")
	w.Header().Set("Connection", "keep-alive")
	w.WriteHeader(http.StatusOK)

	flusher, ok := w.(http.Flusher)
	if !ok {
		return
	}

	// Send all current docs as update events
	for i := range initial {
		sendSSEUpdate(w, flusher, &initial[i])
	}

	ticker := time.NewTicker(15 * time.Second)
	defer ticker.Stop()

	for {
		select {
		case <-r.Context().Done():
			return
		case event, open := <-ch:
			if !open {
				return
			}
			// Filter by interval for collection subscriptions
			if event.Type == "update" && event.Doc != nil {
				// Check if doc name is in interval
				docName := lastComponent(event.Path)
				if isInInterval(docName, start, end) {
					sendSSEUpdate(w, flusher, event.Doc)
				}
			} else if event.Type == "delete" {
				sendSSEDelete(w, flusher, event.Path)
			}
		case <-ticker.C:
			fmt.Fprintf(w, ": keepalive\n\n")
			flusher.Flush()
		}
	}
}

// sendSSEUpdate sends an SSE update event.
func sendSSEUpdate(w http.ResponseWriter, flusher http.Flusher, doc *store.DocResult) {
	data, err := json.Marshal(map[string]interface{}{
		"path": doc.Path,
		"doc":  doc.Doc,
		"meta": doc.Meta,
	})
	if err != nil {
		return
	}
	id := time.Now().UnixMilli()
	fmt.Fprintf(w, "event: update\ndata: %s\nid: %d\n\n", string(data), id)
	flusher.Flush()
}

// sendSSEDelete sends an SSE delete event.
func sendSSEDelete(w http.ResponseWriter, flusher http.Flusher, path string) {
	pathJSON, _ := json.Marshal(path)
	id := time.Now().UnixMilli()
	fmt.Fprintf(w, "event: delete\ndata: %s\nid: %d\n\n", string(pathJSON), id)
	flusher.Flush()
}

// readBody reads and returns the request body.
func readBody(r *http.Request) ([]byte, error) {
	if r.Body == nil {
		return nil, fmt.Errorf("empty request body")
	}
	var buf []byte
	tmp := make([]byte, 4096)
	for {
		n, err := r.Body.Read(tmp)
		if n > 0 {
			buf = append(buf, tmp[:n]...)
		}
		if err != nil {
			break
		}
	}
	if len(buf) == 0 {
		return []byte("{}"), nil
	}
	return buf, nil
}

// joinComponents joins path components with "/".
func joinComponents(components []string) string {
	return strings.Join(components, "/")
}

// lastComponent returns the last component of a path.
func lastComponent(path string) string {
	path = strings.TrimSuffix(path, "/")
	idx := strings.LastIndex(path, "/")
	if idx < 0 {
		return path
	}
	return path[idx+1:]
}

// isInInterval checks if a name is within an interval [start, end].
func isInInterval(name, start, end string) bool {
	if start != "" && name < start {
		return false
	}
	if end != "" && name > end {
		return false
	}
	return true
}

