func (s *Store) DeleteDatabase(name string) error {
	// Save subs before removal so we can notify after removal
	db, found := s.databases.Find(name)
	if !found {
		return ErrNotFound
	}
	savedSubs := db.subs

	_, removed := s.databases.Remove(name)
	if !removed {
		return ErrNotFound
	}

	// Notify database-level collection subscribers
	path := "/v1/" + name + "/"
	savedSubs.broadcast(Event{Type: "delete", Path: path})

	return nil
}

